import { ChangeDetectorRef, Component, Inject, OnInit, ElementRef, Renderer2, AfterViewInit, ViewChild } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { Invoice } from '../../models/invoice';
import { InvoiceService } from '../../services/invoice.service';
import { CommonModule } from '@angular/common';
import { Router, RouterLink } from '@angular/router';
import { InvoiceStatusPipe } from '../../pipes/invoice-status.pipe'
import { InvoiceCustomerPipe } from '../../pipes/invoice-customer.pipe'
import { CustomerService } from '../../services/customer.service';
import { Customer } from '../../models/customer';
import { UserService } from '../../services/users.service';
import { MatPaginatorModule, PageEvent, MatPaginator } from '@angular/material/paginator';
import { MatTableDataSource } from '@angular/material/table';

const ELEMENT_DATA: Invoice[] = [];

@Component({
  selector: 'invoice-list',
  imports: [CommonModule, RouterLink, InvoiceStatusPipe, InvoiceCustomerPipe, MatPaginatorModule],
  templateUrl: './invoice-list.component.html',
  styleUrls: ['./invoice-list.component.css'],
  standalone: true
})
export class InvoiceListComponent implements OnInit, AfterViewInit {

  public invoices: Invoice[] = [];
  public customers: Customer[] = [];
  private invoiceStatuses: { [statusId: number]: string; } = {};
  private filterElement: any;
  private filterCaptionElement: any;

  
  public itemsPerPage: number = 5;
  
  displayedColumns: string[] = ['Id', 'Customer', 'InvoiceDate', 'DueDate',
    'InvoiceAmount', 'PaidAmount', 'Balance', 'Status'];

  dataSource = new MatTableDataSource<Invoice>();
  totalItems = 0;
  pageSize = 10;
  currentPage = 0;

  constructor(
    http: HttpClient,
    @Inject('BASE_URL') baseUrl: string,
    private readonly invoiceService: InvoiceService,
    private readonly changeDetectorRef: ChangeDetectorRef,
    private readonly router: Router,
    private readonly customerService: CustomerService,
    private readonly elementRef: ElementRef,
    private readonly renderer: Renderer2,
    public userService: UserService
  ) {
    const invoicesEndPoint = baseUrl + 'api/invoice/all';
    console.log("End point :" + invoicesEndPoint);    
  }

  pageEvent: PageEvent = null as unknown as PageEvent;

  @ViewChild(MatPaginator) paginator!: MatPaginator;

  ngAfterViewInit(): void {
    this.dataSource.paginator = this.paginator;
  }

  handlePageEvent(event: PageEvent): void {
    this.currentPage = event.pageIndex;
    this.pageSize = event.pageSize;
    //this.loadData(this.currentPage, this.pageSize);
  }

  ngOnInit(): void {

    this.filterElement = document.getElementById('filter')!;
    this.filterCaptionElement = document.getElementById('filter-caption')!;

    this.loadInvoiceStatuses();
    this.loadInvoices();
    this.loadCustomers();
  }

  loadCustomers() {
    this.customerService.getAll()
      .subscribe((data) => {
        console.log("Pipe ...found data " + data.length);
        this.customers = data;
        this.changeDetectorRef.detectChanges();
      });
  }

  loadInvoiceStatuses() {
    this.invoiceStatuses = ["UnPaid", "Partially Paid", "Paid", "Over Due"];
  }

  loadInvoices() {
    this.invoiceService.getAll()
      .subscribe((data) => {

        this.invoices = data;

        this.dataSource.data = data; // Assuming response has an 'items' array
        this.totalItems = data.length; // Assuming response has a 'totalCount' property

        this.changeDetectorRef.detectChanges();
      });
  }

  viewDetails(id: number) {
    this.router.navigate(['/invoice-form/' + id])
  }

  AddNew() {    
    this.router.navigate(['/invoice-form'])
  }

  filterBy(filterBy: string) {    
    console.log("filer el :" + this.filterElement.className);
    
    if (this.filterElement) {
      this.renderer.removeClass(this.filterElement, 'filter');
    }

    if (this.filterCaptionElement) {
      this.filterCaptionElement.innerText = "Filtered by: " + filterBy;
    }

    const elements = this.elementRef.nativeElement.querySelectorAll('.trans-row');
    elements.forEach((element: HTMLElement) => {
      if (element.classList.contains(filterBy)) {
        element.style.display = '';        
      } else {
        element.style.display = 'none';
      }
    });
  }

  clearFilter() {
    const elements = this.elementRef.nativeElement.querySelectorAll('.trans-row');
    elements.forEach((element: HTMLElement) => {
      element.style.display = '';
    });

    this.renderer.addClass(this.filterElement, 'filter');
  }

  getSummaryByStatusId(statusId: number): number {
    return this.invoices.filter(x => x.statusId === statusId).length;      
  }

  getBalanceSummary(): number {
    return this.invoices.filter(x => x.balance)
      .reduce((sum, t) => sum + t.balance, 0);
  }

  getPaidSummary(): number {
    return this.invoices.filter(x => x.paidAmount)
      .reduce((sum, t) => sum + t.paidAmount, 0);
  }

}
<div class="row mb-4 g-4">
  <div class="col-md-3 ">
    <div (click)="filterBy('Paid')" class="card h-100 Paid text-white">
      <div class="card-body">
        <h5 class="card-title">Paid</h5>
        <h3 class="card-title">{{getSummaryByStatusId(2)}}</h3>
      </div>
    </div>
  </div>
  <div class="col-md-3 ">
    <div (click)="filterBy('PartiallyPaid')" class="card h-100 PartiallyPaid text-white">
      <div class="card-body">
        <h5 class="card-title">Partially Paid</h5>
        <h3 class="card-title">{{getSummaryByStatusId(1)}}</h3>
      </div>
    </div>
  </div>
  <div class="col-md-3 ">
    <div (click)="filterBy('UnPaid')" class="card h-100 UnPaid text-white">
      <div class="card-body">
        <h5 class="card-title">UnPaid</h5>
        <h3 class="card-title">{{getSummaryByStatusId(0)}}</h3>
      </div>
    </div>
  </div>
  <div class="col-md-3 ">
    <div (click)="filterBy('OverDue')" class="card h-100 OverDue text-white">
      <div class="card-body">
        <h5 class="card-title">Over Due</h5>
        <h3 class="card-title">{{ getSummaryByStatusId(3)}}</h3>
      </div>
    </div>
  </div>
</div>

<div class="row mb-4 g-4">

    <div class="col-md-6 d-flex">
      <span id="tableLabel" class="col-md-3 invoice-title">Invoices</span>

      <a class="btn me-2 col-md-3"
         *ngIf="userService.isAdmin()"
         (click)="AddNew()">
        <li class="bi bi-plus-circle"> Add New</li>
      </a>

      <div id="filter" style="display:none;" class="col-md-6 filter my-2 d-flex">
        <div id="filter-caption" class="col-md-6">
          filter by
        </div>
        <div class="col-md-6 clear-filter">
          <a (click)='clearFilter()'>[ Clear ]</a>
        </div>        
      </div>
    </div>

    <div class="col-md-6 d-flex">

      <div class="card h-2 col-md-5 mx-2">
        <div class="card-body">
          <span class="card-title btitle">Total Outstanding</span>
          <span class="card-title mx-2">: {{getBalanceSummary() | currency:'R'}}</span>
        </div>
      </div>

      <div class="card h-2 col-md-5 mx-2">
        <div class="card-body">
          <span class="card-title btitle">Total Paid</span>
          <span class="card-title mx-2">: {{getPaidSummary() | currency:'R'}}</span>
        </div>
      </div>

    </div>


  </div>

  <p *ngIf="!invoices?.length"><em>Loading...</em></p>

  <table class="table table-striped py-2 table-hover align-middle" *ngIf="invoices.length">
    <thead>
      <tr>
        <th scope="col">Id</th>
        <th scope="col">Customer</th>
        <th scope="col">InvoiceDate</th>

        <th scope="col">DueDate</th>
        <th scope="col">InvoiceAmount</th>
        <th scope="col">PaidAmount</th>
        <th scope="col">Balance</th>
        <th scope="col">Status</th>
      </tr>
    </thead>
    <tbody>
      <tr *ngFor="let inv of invoices"
          class="trans-row"
          [ngClass]="inv.statusId | invoiceStatusPipe:true"
          (click)="viewDetails(inv.invoiceNumber)">
        <td>{{ inv.invoiceNumber }}</td>
        <td>{{ inv.customerId | invoiceCustomerPipe: customers }}</td>
        <td>{{ inv.invoiceDate | date:'MM/dd/yyyy, h:mm a' }}</td>

        <td>{{ inv.dueDate | date:'MM/dd/yyyy, h:mm a' }}</td>
        <td>{{ inv.invoiceAmount | currency:'R' }}</td>
        <td>{{ inv.paidAmount | currency:'R'  }}</td>
        <td>{{ inv.balance | currency:'R'  }}</td>
        <td>{{ inv.statusId | invoiceStatusPipe }}</td>
      </tr>
    </tbody>
  </table>




  <div class="mat-elevation-z8">
    <mat-table [dataSource]="dataSource">

      <!-- Define your columns here (example) -->
      <ng-container matColumnDef="invoiceNumber">
        <mat-header-cell *matHeaderCellDef> Invoice Number </mat-header-cell>
        <mat-cell *matCellDef="let element"> {{element.invoiceNumber}} </mat-cell>
      </ng-container>
      <ng-container matColumnDef="name">
        <mat-header-cell *matHeaderCellDef> Customer </mat-header-cell>
        <mat-cell *matCellDef="let element"> {{ element.customerId | invoiceCustomerPipe: customers }} </mat-cell>
      </ng-container>
      <ng-container matColumnDef="invoiceDate">
        <mat-header-cell *matHeaderCellDef> InvoiceDate </mat-header-cell>
        <mat-cell *matCellDef="let element"> {{ inv.invoiceDate | date:'MM/dd/yyyy, h:mm a' }} </mat-cell>
      </ng-container>
      <ng-container matColumnDef="dueDate">
        <mat-header-cell *matHeaderCellDef> Due Date </mat-header-cell>
        <mat-cell *matCellDef="let element"> {{ inv.dueDate | date:'MM/dd/yyyy, h:mm a' }} </mat-cell>
      </ng-container>


      <ng-container matColumnDef="id">
        <mat-header-cell *matHeaderCellDef> ID </mat-header-cell>
        <mat-cell *matCellDef="let element"> {{element.invoiceNumber}} </mat-cell>
      </ng-container>
      <ng-container matColumnDef="id">
        <mat-header-cell *matHeaderCellDef> ID </mat-header-cell>
        <mat-cell *matCellDef="let element"> {{element.invoiceNumber}} </mat-cell>
      </ng-container>
      <ng-container matColumnDef="id">
        <mat-header-cell *matHeaderCellDef> ID </mat-header-cell>
        <mat-cell *matCellDef="let element"> {{element.invoiceNumber}} </mat-cell>
      </ng-container>


      <mat-header-row *matHeaderRowDef="displayedColumns"></mat-header-row>
      <mat-row *matRowDef="let row; columns: displayedColumns;"></mat-row>
    </mat-table>

    <mat-paginator #paginator
                   [length]="totalItems"
                   [pageSize]="pageSize"
                   [pageSizeOptions]="[5, 10, 25, 100]"
                   (page)="handlePageEvent($event)"
                   showFirstLastButtons
                   aria-label="Select page of items">
    </mat-paginator>
  </div>
